<script>
(function () {
  function parseRgb(str) {
    const m = String(str).match(/rgba?\(\s*([\d.]+)\s*,\s*([\d.]+)\s*,\s*([\d.]+)(?:\s*,\s*[\d.]+)?\s*\)/i);
    if (!m) return null;
    return { r: +m[1], g: +m[2], b: +m[3] };
  }
  function luminance({ r, g, b }) {
    const srgb = [r, g, b].map(v => {
      v = v / 255;
      return v <= 0.03928 ? v / 12.92 : Math.pow((v + 0.055) / 1.055, 2.4);
    });
    return 0.2126 * srgb[0] + 0.7152 * srgb[1] + 0.0722 * srgb[2];
  }
  function decideThemeFromBg(bg) {
    const rgb = parseRgb(bg);
    if (!rgb) return null;
    return luminance(rgb) < 0.35 ? "dark" : "light";
  }

  try {
    if (window.parent && window.parent !== window) {
      const pdoc = window.parent.document;
      const parentRoot = pdoc.documentElement;

      // Copy CSS vars
      const parentStyles = window.parent.getComputedStyle(parentRoot);
      const iframeRoot = document.documentElement;

      Array.from(parentStyles).forEach(prop => {
        if (!prop.startsWith("--")) return;
        iframeRoot.style.setProperty(prop, parentStyles.getPropertyValue(prop));
      });

      // Set data-theme based on host background
      const bodyBg = window.parent.getComputedStyle(pdoc.body).backgroundColor;
      const htmlBg = window.parent.getComputedStyle(parentRoot).backgroundColor;
      const theme = decideThemeFromBg(bodyBg) || decideThemeFromBg(htmlBg);
      if (theme) document.documentElement.setAttribute("data-theme", theme);
    }
  } catch (e) {
    // Cross-origin: ignore. Canvas/CanvasText will still work.
  }
})();
</script>

