<style>
:root {
  color-scheme: light dark;

  --host-bg: rgb(var(--v-theme-cfxbackground, 255,255,255));
  --host-fg: rgb(var(--v-theme-cfxtext, 0,0,0));
}

html, body {
  background: var(--host-bg) !important;
  color: var(--host-fg) !important;
}

.conversation-wrapper {
  background: var(--host-bg);
  color: var(--host-fg);

  --bg-primary: var(--host-bg);
  --bg-secondary: color-mix(in srgb, var(--host-fg) 6%, var(--host-bg));
  --bg-card: color-mix(in srgb, var(--host-fg) 4%, var(--host-bg));
  --bg-modal: color-mix(in srgb, var(--host-fg) 10%, var(--host-bg));
  --bg-modal-header: color-mix(in srgb, var(--host-fg) 12%, var(--host-bg));

  --text-primary: var(--host-fg);
  --text-secondary: color-mix(in srgb, var(--host-fg) 78%, transparent);
  --text-tertiary: color-mix(in srgb, var(--host-fg) 55%, transparent);

  --border-color: color-mix(in srgb, var(--host-fg) 18%, transparent);
  --border-light: color-mix(in srgb, var(--host-fg) 12%, transparent);
  --border-separator: color-mix(in srgb, var(--host-fg) 30%, transparent);

  --shadow: color-mix(in srgb, var(--host-fg) 14%, transparent);
  --hover-bg: color-mix(in srgb, var(--host-fg) 8%, transparent);
  --modal-overlay: color-mix(in srgb, var(--host-fg) 80%, transparent);

  /* Accent colors */
  --accent-blue: #4da6ff;
  --accent-blue-light: #66b3ff;
  --accent-blue-dark: #0066cc;
  --accent-orange: #ff9933;
  --accent-green: #00ff00;
  --accent-red: #dc3545;
  --accent-grey: #9ca3af;
}

/* Reset body and html margins/padding */
body, html {
  margin: 0 !important;
  padding: 0 !important;
  background-color: var(--host-bg) !important;
  overflow: hidden;
}

/* Custom styling for details/summary */
details > summary {
  position: relative;
}

details > summary::-webkit-details-marker {
  display: none;
}

details > summary::marker {
  display: none;
}

/* Rotate arrow when closed */
details:not([open]) .collapse-arrow {
  transform: rotate(-90deg);
  display: inline-block;
}

.collapse-arrow {
  transition: transform 0.3s ease;
  display: inline-block;
}

/* Modal styles */
.dashboard-modal {
  display: none;
  position: fixed;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  background-color: var(--modal-overlay);
  z-index: 10000;
  animation: fadeIn 0.3s ease;
}

.dashboard-modal.show {
  display: flex;
  align-items: center;
  justify-content: center;
}

.dashboard-modal-content {
  background-color: var(--bg-modal);
  width: 90%;
  height: 90%;
  border-radius: 8px;
  box-shadow: 0 4px 20px var(--shadow);
  display: flex;
  flex-direction: column;
  animation: slideIn 0.3s ease;
}

.dashboard-modal-header {
  padding: 15px 20px;
  background-color: var(--bg-modal-header);
  border-bottom: 1px solid var(--border-color);
  display: flex;
  justify-content: space-between;
  align-items: center;
  border-radius: 8px 8px 0 0;
}

.dashboard-modal-title {
  color: var(--text-primary);
  font-size: 16px;
  font-weight: 600;
  margin: 0;
}

.dashboard-modal-close {
  background: none;
  border: none;
  color: var(--text-primary);
  font-size: 24px;
  cursor: pointer;
  padding: 0;
  width: 30px;
  height: 30px;
  display: flex;
  align-items: center;
  justify-content: center;
  border-radius: 4px;
  transition: background-color 0.2s ease;
}

.dashboard-modal-close:hover {
  background-color: var(--hover-bg);
}

.dashboard-modal-body {
  flex: 1;
  overflow-y: auto;
  overflow-x: hidden;
  padding: 0;
  background-color: var(--bg-primary);
  color: var(--text-primary);
}

.dashboard-modal-iframe {
  width: 100%;
  height: 100%;
  border: none;
}

@keyframes fadeIn {
  from { opacity: 0; }
  to { opacity: 1; }
}

@keyframes slideIn {
  from { 
    transform: translateY(-50px);
    opacity: 0;
  }
  to { 
    transform: translateY(0);
    opacity: 1;
  }
}
</style>

<script>
function launchConversationDetails(conversationId, conversationLabel) {
    // Extract root parent ID (before first colon) to always show full conversation
    const rootParentId = conversationId.split(':')[0];
    
    // Ensure conversation_id is properly formatted - use the full ID for conversation_id
    // but parent_conv_id should always be the root (base) ID
    const cfxAction = {
        type: "GO_TO_APP_STATE",
        label: "View Conversation Details",
        appName: "user-dashboard/ai_conversation_details_app",
        contexts: {
            parent_conv_id: rootParentId,
            conversation_id: conversationId,
            conversationId: conversationId,
            conv_id: conversationId,
            request_type: "Copilot",
            conversationLabel: conversationLabel || "AIOPS"
        }
    };
    
    console.log('launchConversationDetails - conversationId:', conversationId);
    console.log('launchConversationDetails - rootParentId:', rootParentId);
    console.log('launchConversationDetails - contexts:', cfxAction.contexts);
    
    window.top.postMessage(cfxAction, '*');
}

function showMessageDetails(conversationId, promptId, conversationLabel) {
    console.log('=== showMessageDetails CALLED ===');
    console.log('conversationId:', conversationId);
    console.log('promptId:', promptId);
    console.log('conversationLabel:', conversationLabel);
    
    // Show modal first with loading indicator
    showDashboardModal(conversationLabel || 'Message Details', true);
    
    const modalBody = document.getElementById('dashboard-modal-body');
    const loadingIndicator = document.getElementById('dashboard-loading-indicator');
    
    // Get the current URL structure to build the correct dashboard URL
    const currentUrl = new URL(window.location.href);
    const baseUrl = currentUrl.origin;
    
    // Extract root parent ID for context
    const rootParentId = conversationId.split(':')[0];
    
    // Build context parameters
    const contextParams = {
        parent_conv_id: rootParentId,
        conversation_id: conversationId,
        conversationId: conversationId,
        conv_id: conversationId,
        prompt_id: promptId || '',
        request_type: "Copilot",
        conversationLabel: conversationLabel || "AIOPS"
    };
    
    // Build tabs parameter URL (most reliable method)
    const tabConfig = {
        label: conversationLabel || "Message Details",
        appId: "featureApp0",
        appMetadata: {
            appName: "user-dashboard/ai_conversation_details",
            ...contextParams
        }
    };
    const tabsParam = encodeURIComponent(JSON.stringify([tabConfig]));
    const tabsUrl = `${baseUrl}/app?tabs=${tabsParam}`;
    
    // Try multiple URL formats to find the correct dashboard endpoint
    const urlFormats = [
        tabsUrl, // Try tabs parameter first (most reliable)
        `${baseUrl}/app/user-dashboard/ai_conversation_details?conversation_id=${encodeURIComponent(conversationId)}`,
        `${baseUrl}/app?appName=user-dashboard/ai_conversation_details&conversation_id=${encodeURIComponent(conversationId)}`,
        `${baseUrl}/app/user-dashboard/ai_conversation_details_app?conversation_id=${encodeURIComponent(conversationId)}`
    ];
    
    let currentUrlIndex = 0;
    
    function tryNextUrl() {
        if (currentUrlIndex >= urlFormats.length) {
            // All URLs failed, show error
            if (loadingIndicator) {
                loadingIndicator.style.display = 'none';
            }
            if (modalBody) {
                modalBody.innerHTML = `
                    <div style="padding: 40px; text-align: center; color: var(--text-primary); background-color: var(--bg-primary);">
                        <p style="margin-bottom: 10px; color: var(--accent-red);">Unable to load dashboard content.</p>
                        <p style="color: var(--text-secondary); font-size: 0.9rem; margin-bottom: 20px;">All URL formats failed. The dashboard may need to be opened in a new tab.</p>
                        <button onclick="launchConversationDetails('${conversationId}', '${conversationLabel || 'AIOPS'}')" style="padding: 10px 20px; background: var(--accent-blue); color: var(--bg-primary); border: none; border-radius: 6px; cursor: pointer; font-weight: 600;">Open in New Tab</button>
                    </div>
                `;
            }
            return;
        }
        
        const dashboardUrl = urlFormats[currentUrlIndex];
        console.log(`Trying URL ${currentUrlIndex + 1}/${urlFormats.length}:`, dashboardUrl);
        
        fetch(dashboardUrl, {
            method: 'GET',
            credentials: 'same-origin',
            headers: {
                'Accept': 'text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8'
            }
        })
        .then(response => {
            console.log(`Response status for URL ${currentUrlIndex + 1}:`, response.status, response.statusText);
            if (!response.ok) {
                throw new Error(`HTTP ${response.status}`);
            }
            return response.text();
        })
        .then(html => {
            console.log(`Received HTML from URL ${currentUrlIndex + 1}, length:`, html.length);
            
            // Check if we got actual content (not just an error page or redirect)
            if (html.length < 1000 || html.includes('error') || html.includes('404') || html.includes('Not Found')) {
                throw new Error('Invalid response content');
            }
            
            if (loadingIndicator) {
                loadingIndicator.style.display = 'none';
            }
            
            if (modalBody) {
                // Extract the main content from the HTML
                const parser = new DOMParser();
                const doc = parser.parseFromString(html, 'text/html');
                
                // Look for the main content div - try multiple strategies
                let content = null;
                
                // Strategy 1: Find div with overflow style (the template wrapper from the shared template)
                // The template starts with: <div style="overflow: auto; width: 100%; height: 100%; background-color: #000000;...
                content = doc.querySelector('div[style*="overflow"]') || 
                         doc.querySelector('div[style*="overflow: auto"]') ||
                         doc.querySelector('div[style*="overflow:auto"]');
                
                // Strategy 2: Find div with background-color #000000 and overflow
                if (!content) {
                    const allDivs = doc.querySelectorAll('div');
                    for (let div of allDivs) {
                        const style = div.getAttribute('style') || '';
                        if (style.includes('background-color') && 
                            (style.includes('#000000') || style.includes('black')) &&
                            (style.includes('overflow') || style.includes('width: 100%'))) {
                            content = div;
                            break;
                        }
                    }
                }
                
                // Strategy 3: Find div containing table (the dashboard has tables)
                if (!content) {
                    const divsWithTables = doc.querySelectorAll('div');
                    for (let div of divsWithTables) {
                        if (div.querySelector('table')) {
                            content = div;
                            break;
                        }
                    }
                }
                
                // Strategy 4: Find body's main content area (skip navigation/sidebar)
                if (!content) {
                    const bodyDivs = doc.querySelectorAll('body > div');
                    for (let div of bodyDivs) {
                        // Skip common wrapper divs
                        const id = div.getAttribute('id') || '';
                        const className = div.getAttribute('class') || '';
                        if (!id.includes('nav') && !className.includes('nav') && 
                            !id.includes('sidebar') && !className.includes('sidebar')) {
                            content = div;
                            break;
                        }
                    }
                }
                
                // Strategy 5: Use body content directly
                if (!content) {
                    content = doc.body;
                }
                
                if (content && content.innerHTML) {
                    // Get the innerHTML and clean it up
                    let contentHtml = content.innerHTML;
                    
                    // Remove script tags to prevent execution issues
                    contentHtml = contentHtml.replace(/<script\b[^<]*(?:(?!<\/script>)<[^<]*)*<\/script>/gi, '');
                    
                    // Remove style tags (we'll add our own)
                    contentHtml = contentHtml.replace(/<style\b[^<]*(?:(?!<\/style>)<[^<]*)*<\/style>/gi, '');
                    
                    modalBody.innerHTML = contentHtml;
                    
                    console.log('Successfully loaded dashboard content');
                } else {
                    throw new Error('Could not extract content from response');
                }
                
                // Ensure all styles are preserved and no white backgrounds
                if (!document.getElementById('modal-content-style')) {
                    const style = document.createElement('style');
                    style.id = 'modal-content-style';
                    style.textContent = `
                        #dashboard-modal-body {
                            background-color: var(--bg-primary) !important;
                            color: var(--text-primary) !important;
                            padding: 20px !important;
                        }
                        #dashboard-modal-body * {
                            color: inherit !important;
                        }
                        #dashboard-modal-body table {
                            background-color: transparent !important;
                            color: var(--text-primary) !important;
                        }
                        #dashboard-modal-body td {
                            background-color: transparent !important;
                            color: var(--text-primary) !important;
                        }
                        #dashboard-modal-body div {
                            background-color: transparent !important;
                        }
                    `;
                    document.head.appendChild(style);
                }
                
                // Scroll to top
                modalBody.scrollTop = 0;
            }
        })
        .catch(error => {
            console.error(`Error with URL ${currentUrlIndex + 1}:`, error);
            currentUrlIndex++;
            // Try next URL
            setTimeout(tryNextUrl, 100);
        });
    }
    
    // Start trying URLs
    tryNextUrl();
}

function showDashboardModal(title, showLoading) {
    // Create modal if it doesn't exist
    let modal = document.getElementById('dashboard-modal');
    if (!modal) {
        modal = document.createElement('div');
        modal.id = 'dashboard-modal';
        modal.className = 'dashboard-modal';
        document.body.appendChild(modal);
        
        // Close on background click
        modal.addEventListener('click', function(e) {
            if (e.target === modal) {
                closeDashboardModal();
            }
        });
        
        // Close on Escape key
        document.addEventListener('keydown', function(e) {
            if (e.key === 'Escape' && modal.classList.contains('show')) {
                closeDashboardModal();
            }
        });
    }
    
    // Build modal content
    const loadingHtml = showLoading ? '<div style="padding: 40px; text-align: center; color: var(--text-primary);"><div style="margin-bottom: 20px;">Loading dashboard...</div><div style="border: 3px solid var(--accent-blue); border-top: 3px solid transparent; border-radius: 50%; width: 40px; height: 40px; animation: spin 1s linear infinite; margin: 0 auto;"></div></div>' : '';
    
    modal.innerHTML = `
        <div class="dashboard-modal-content">
            <div class="dashboard-modal-header">
                <h3 class="dashboard-modal-title">${title}</h3>
                <button class="dashboard-modal-close" onclick="closeDashboardModal()">&times;</button>
            </div>
            <div id="dashboard-modal-body" class="dashboard-modal-body">
                ${loadingHtml}
            </div>
        </div>
    `;
    
    // Add spinner animation if needed
    if (showLoading) {
        let style = document.getElementById('modal-spinner-style');
        if (!style) {
            style = document.createElement('style');
            style.id = 'modal-spinner-style';
            style.textContent = '@keyframes spin { 0% { transform: rotate(0deg); } 100% { transform: rotate(360deg); } }';
            document.head.appendChild(style);
        }
    }
    
    // Show modal
    modal.classList.add('show');
}

function closeDashboardModal() {
    const modal = document.getElementById('dashboard-modal');
    if (modal) {
        modal.classList.remove('show');
        // Clear modal body content
        const modalBody = document.getElementById('dashboard-modal-body');
        if (modalBody) {
            modalBody.innerHTML = '';
        }
    }
}

function toggleChildren(parentPromptId) {
    // Find all items where prompt_id starts with parentPromptId:
    const allItems = document.querySelectorAll('[data-prompt-id]');
    const arrow = document.querySelector('[data-prompt-id="' + parentPromptId + '"] .collapse-arrow');
    
    let children = [];
    allItems.forEach(item => {
        const itemPromptId = item.getAttribute('data-prompt-id');
        // Direct children: prompt_id starts with parentPromptId: and has no further colons
        if (itemPromptId && itemPromptId.startsWith(parentPromptId + ':')) {
            const suffix = itemPromptId.substring(parentPromptId.length + 1);
            if (suffix && !suffix.includes(':')) {
                children.push(item);
            }
        }
    });
    
    if (children.length === 0) return;
    
    // Check if children are currently visible
    const isVisible = children[0].style.display !== 'none';
    
    // Toggle visibility recursively
    function toggleDescendants(promptId, shouldHide) {
        allItems.forEach(item => {
            const itemPromptId = item.getAttribute('data-prompt-id');
            if (itemPromptId && itemPromptId.startsWith(promptId + ':')) {
                const suffix = itemPromptId.substring(promptId.length + 1);
                if (suffix && !suffix.includes(':')) {
                    // This is a direct child
                    if (shouldHide) {
                        item.style.display = 'none';
                        // Also collapse the child's arrow
                        const childArrow = item.querySelector('.collapse-arrow');
                        if (childArrow) childArrow.style.transform = 'rotate(-90deg)';
                        toggleDescendants(itemPromptId, true);
                    } else {
                        item.style.display = 'flex';
                    }
                }
            }
        });
    }
    
    if (isVisible) {
        toggleDescendants(parentPromptId, true);
        if (arrow) arrow.style.transform = 'rotate(-90deg)';
    } else {
        children.forEach(child => child.style.display = 'flex');
        if (arrow) arrow.style.transform = 'rotate(0deg)';
    }
}

function togglePromptExpansion(element) {
    // Find the text container
    const textContainer = element.closest('.text-container');
    if (!textContainer) return;
    
    const innerDiv = textContainer.querySelector('div');
    if (!innerDiv) return;
    
    if (element.classList.contains('expanded')) {
        element.classList.remove('expanded');
        innerDiv.style.whiteSpace = 'nowrap';
        innerDiv.style.overflow = 'hidden';
        innerDiv.style.textOverflow = 'ellipsis';
    } else {
        element.classList.add('expanded');
        innerDiv.style.whiteSpace = 'normal';
        innerDiv.style.overflow = 'visible';
        innerDiv.style.textOverflow = 'clip';
        innerDiv.style.wordBreak = 'break-word';
    }
}

function checkTruncation(element) {
    // Find the parent div that has the truncation styles
    const parentDiv = element.closest('.text-container');
    if (!parentDiv) return;
    
    const textDiv = parentDiv.querySelector('div');
    if (!textDiv) return;
    
    // Check if text is truncated
    if (textDiv.scrollWidth > textDiv.clientWidth) {
        textDiv.style.cursor = 'pointer';
        textDiv.title = 'Click to expand';
    } else {
        textDiv.style.cursor = 'default';
        textDiv.title = '';
    }
}

// Check truncation on window load and resize
window.addEventListener('load', function() {
    document.querySelectorAll('.prompt-text').forEach(checkTruncation);
});

window.addEventListener('resize', function() {
    document.querySelectorAll('.prompt-text').forEach(checkTruncation);
});
</script>

{% endraw %}
{# Extract root parent ID from conversation_id if it contains colons #}
{%- if conversation_id is defined and conversation_id != "" and ":" in conversation_id -%}
  {%- set root_parent_from_conv_id = conversation_id.split(":")[0] -%}
{%- else -%}
  {%- set root_parent_from_conv_id = "" -%}
{%- endif -%}

{# Set parent_conv_id - always use root (base) ID, not the full conversation_id with colons #}
{%- if parent_conv_id is not defined or parent_conv_id == "" -%}
  {%- if root_parent_from_conv_id != "" -%}
    {%- set parent_conv_id = root_parent_from_conv_id -%}
  {%- elif conv_id is defined and conv_id != "" -%}
    {%- if ":" in conv_id -%}
      {%- set parent_conv_id = conv_id.split(":")[0] -%}
    {%- else -%}
      {%- set parent_conv_id = conv_id -%}
    {%- endif -%}
  {%- elif conversation_id is defined and conversation_id != "" -%}
    {%- if ":" in conversation_id -%}
      {%- set parent_conv_id = conversation_id.split(":")[0] -%}
    {%- else -%}
      {%- set parent_conv_id = conversation_id -%}
    {%- endif -%}
  {%- endif -%}
{%- else -%}
  {# Ensure parent_conv_id is root (base) ID even if it was provided with colons #}
  {%- if ":" in parent_conv_id -%}
    {%- set parent_conv_id = parent_conv_id.split(":")[0] -%}
  {%- endif -%}
{%- endif -%}

{# Set conv_id if not provided #}
{%- if conv_id is not defined or conv_id == "" -%}
  {%- set conv_id = conversation_id if (conversation_id is defined and conversation_id != "") else parent_conv_id -%}
{%- endif -%}

{# Set conversation_id if not provided - use conv_id as fallback #}
{%- if conversation_id is not defined or conversation_id == "" -%}
  {%- if conv_id is defined and conv_id != "" -%}
    {%- set conversation_id = conv_id -%}
  {%- else -%}
    {%- set conversation_id = parent_conv_id -%}
  {%- endif -%}
{%- endif -%}

{% set llm_cost_query = ' * GET llm_name, input_token_cost_per1M, output_token_cost_per1M' %}
{% set llm_costs = engine.query_stream_data(
    "llm_model_costs",
    cfxql_query=llm_cost_query,
    sorting=[{"llm_name": "asc"}],
    limit=100,
    max_rows=100
) %}

{% set costs = dict() %}
{% for cost_row in llm_costs %}
  {% set _ = costs.update({
    cost_row.llm_name: [
      cost_row.input_token_cost_per1M | float,
      cost_row.output_token_cost_per1M | float
    ]
  }) %}
{% endfor %}

{%- set cfxql_query2 =
    "conversationId contains '"+ parent_conv_id +
    "' GET USER_ID, persona, ai_project_name, message, conversationLabel, timestamp, type, llm, " +
    "tool_name, tool_content, codeBlocks, isToolCall, _RDA_Id, conversationId, request_type, prompt_id"
-%}

{%- set convs = engine.query_stream_data(
    "rda_chat_sessions",
    cfxql_query=cfxql_query2,
    sorting=[{"timestamp": "asc"}, {"_RDA_Id": "asc"}],
    limit=1000,
    max_rows=1000
) -%}

{%- if convs -%}
  {# Group conversations by conversationId #}
  {%- set conv_groups = dict() -%}
  {%- for c in convs -%}
    {%- set cid = c.get("conversationId", "") -%}
    {%- if cid not in conv_groups -%}
      {%- set _ = conv_groups.update({cid: []}) -%}
    {%- endif -%}
    {%- set _ = conv_groups[cid].append(c) -%}
  {%- endfor -%}

  {# Get all conversation IDs from raw data (not just from conv_groups) #}
  {%- set all_cids_set = [] -%}
  {%- for c in convs -%}
    {%- set cid = c.get("conversationId", "") -%}
    {%- if cid and cid not in all_cids_set -%}
      {%- set _ = all_cids_set.append(cid) -%}
    {%- endif -%}
  {%- endfor -%}
  {%- set all_cids = all_cids_set -%}

  {# Build parent-child relationships #}
  {%- set parent_of = dict() -%}
  {%- for cid in all_cids -%}
    {%- set parts = cid.split(":") -%}
    {%- if parts|length > 1 -%}
      {%- set parent_cid = parts[:-1] | join(":") -%}
      {%- set _ = parent_of.update({cid: parent_cid}) -%}
    {%- endif -%}
  {%- endfor -%}

  {# Build list of immediate children for each conversation #}
  {%- set immediate_children = dict() -%}
  {%- for cid in all_cids -%}
    {%- set _ = immediate_children.update({cid: []}) -%}
  {%- endfor -%}
  {%- for cid in all_cids -%}
    {%- set parts = cid.split(":") -%}
    {%- if parts|length > 1 -%}
      {%- set parent_cid = parts[:-1] | join(":") -%}
      {%- if parent_cid in immediate_children -%}
        {%- set _ = immediate_children[parent_cid].append(cid) -%}
      {%- endif -%}
    {%- endif -%}
  {%- endfor -%}

  {# Calculate base cost (equals query) and aggregate cost (contains query) for each conversationId #}
  {%- set prompt_base_costs = dict() -%}
  {%- set prompt_aggregate_costs = dict() -%}
  {%- set conv_prompts_data = dict() -%}
  {%- for cid, messages in conv_groups.items() -%}
    {# Collect type=client messages (prompts) with timestamps and prompt_id #}
    {%- set prompts_data = [] -%}
    {%- for c in messages -%}
      {%- if c.get("type") == "client" -%}
        {%- set prompt_text = c.get("message", "") -%}
        {%- if prompt_text -%}
          {%- set _ = prompts_data.append({
            "text": prompt_text,
            "timestamp": c.get("timestamp", ""),
            "prompt_id": c.get("prompt_id", "")
          }) -%}
        {%- endif -%}
      {%- endif -%}
    {%- endfor -%}
    {%- set _ = conv_prompts_data.update({cid: prompts_data}) -%}
    
    {# Calculate costs for each prompt_id #}
    {%- for prompt_data in prompts_data -%}
      {%- set pid = prompt_data.get("prompt_id", "") -%}
      {%- if pid -%}
        {# Base cost: messages with exact prompt_id match #}
        {%- set base_cost_query = "prompt_id is '" + pid + "' GET llm, token_usage_input_tokens, token_usage_output_tokens" -%}
        {%- set base_cost_data = engine.query_stream_data(
            "rda_chat_sessions",
            cfxql_query=base_cost_query,
            limit=10000,
            max_rows=10000
        ) -%}
        {%- set base_cost_list = [] -%}
        {%- for c in base_cost_data -%}
          {%- set llm_name = c.get("llm", "") | string | trim -%}
          {%- if llm_name and llm_name != "" and costs.get(llm_name) -%}
            {%- set cm = costs.get(llm_name, [0.0, 0.0]) -%}
            {%- set input_tokens = (c.get("token_usage_input_tokens") or 0) | int -%}
            {%- set output_tokens = (c.get("token_usage_output_tokens") or 0) | int -%}
            {%- if input_tokens > 0 or output_tokens > 0 -%}
              {%- set input_cost = (cm[0] | float) * (input_tokens | float) / 1000000.0 -%}
              {%- set output_cost = (cm[1] | float) * (output_tokens | float) / 1000000.0 -%}
              {%- set calculated_cost = input_cost + output_cost -%}
              {%- set _ = base_cost_list.append(calculated_cost) -%}
            {%- endif -%}
          {%- endif -%}
        {%- endfor -%}
        {%- set base_cost = base_cost_list | sum -%}
        {%- set _ = prompt_base_costs.update({pid: base_cost | round(4)}) -%}
        
        {# Aggregate cost: messages where prompt_id contains this pid #}
        {%- set aggregate_cost_query = "prompt_id contains '" + pid + "' GET llm, token_usage_input_tokens, token_usage_output_tokens" -%}
        {%- set aggregate_cost_data = engine.query_stream_data(
            "rda_chat_sessions",
            cfxql_query=aggregate_cost_query,
            limit=10000,
            max_rows=10000
        ) -%}
        {%- set aggregate_cost_list = [] -%}
        {%- for c in aggregate_cost_data -%}
          {%- set llm_name = c.get("llm", "") | string | trim -%}
          {%- if llm_name and llm_name != "" and costs.get(llm_name) -%}
            {%- set cm = costs.get(llm_name, [0.0, 0.0]) -%}
            {%- set input_tokens = (c.get("token_usage_input_tokens") or 0) | int -%}
            {%- set output_tokens = (c.get("token_usage_output_tokens") or 0) | int -%}
            {%- if input_tokens > 0 or output_tokens > 0 -%}
              {%- set input_cost = (cm[0] | float) * (input_tokens | float) / 1000000.0 -%}
              {%- set output_cost = (cm[1] | float) * (output_tokens | float) / 1000000.0 -%}
              {%- set calculated_cost = input_cost + output_cost -%}
              {%- set _ = aggregate_cost_list.append(calculated_cost) -%}
            {%- endif -%}
          {%- endif -%}
        {%- endfor -%}
        {%- set aggregate_cost = aggregate_cost_list | sum -%}
        {%- set _ = prompt_aggregate_costs.update({pid: aggregate_cost | round(4)}) -%}
      {%- endif -%}
    {%- endfor -%}
  {%- endfor -%}

  {# Calculate hierarchy level for each conversation ID #}
  {%- set conv_levels = dict() -%}
  {%- for cid in all_cids -%}
    {%- set parts = cid.split(":") -%}
    {%- set level = parts|length - 1 -%}
    {%- set _ = conv_levels.update({cid: level}) -%}
  {%- endfor -%}

  {# Determine if conversation is parent (level 0) or child (level > 0) #}
  {%- set is_parent = dict() -%}
  {%- for cid in all_cids -%}
    {%- set level = conv_levels.get(cid, 0) -%}
    {%- set _ = is_parent.update({cid: (level == 0)}) -%}
  {%- endfor -%}
  
  {# Costs are now calculated per prompt_id, not per conversation_id #}

  {# Collect all prompts with their metadata #}
  {%- set all_prompts_flat = [] -%}
  {%- set cids_in_conv_groups = [] -%}
  {%- set cids_not_in_conv_groups = [] -%}
  {%- for cid in all_cids -%}
    {%- if cid in conv_groups -%}
      {%- set _ = cids_in_conv_groups.append(cid) -%}
      {%- set prompts_data = conv_prompts_data.get(cid, []) -%}
      {%- set sorted_prompts = prompts_data | sort(attribute="timestamp") if prompts_data else [] -%}
      {%- set level = conv_levels.get(cid, 0) -%}
      {%- set parent = is_parent.get(cid, False) -%}
      {# Get persona name and extract agent name #}
      {%- set persona_full = conv_groups[cid][0].get("persona", "") -%}
      {%- set persona_parts = persona_full.split("/") -%}
      {%- set agent_name = (persona_parts[1] if persona_parts|length > 1 else persona_full) + " Agent" -%}
      {# Get conversationLabel #}
      {%- set conversation_label = conv_groups[cid][0].get("conversationLabel", "") -%}
      {# Get parent ID for children #}
      {%- set parent_id = "" -%}
      {%- if not parent -%}
        {%- set parts = cid.split(":") -%}
        {%- if parts|length > 1 -%}
          {%- set parent_id = parts[:-1] | join(":") -%}
        {%- endif -%}
      {%- endif -%}
      {# If no prompts, add a single entry with placeholder #}
      {%- if sorted_prompts -%}
        {%- for prompt_data in sorted_prompts -%}
          {%- set prompt_id = prompt_data.get("prompt_id", "") -%}
          {%- set prompt_base_cost = prompt_base_costs.get(prompt_id, 0.0) -%}
          {%- set prompt_agg_cost = prompt_aggregate_costs.get(prompt_id, 0.0) -%}
          {# Calculate share_pct: for root parents it's 100%, for children it's (base/parent_agg)*100 #}
          {%- set share_pct = 100.0 if parent else 0.0 -%}
          {%- set _ = all_prompts_flat.append({
            "text": prompt_data.text,
            "timestamp": prompt_data.timestamp,
            "prompt_id": prompt_id,
            "cid": cid,
            "level": level,
            "base_cost": prompt_base_cost,
            "aggregate_cost": prompt_agg_cost,
            "is_parent": parent,
            "share_pct": share_pct,
            "agent_name": agent_name,
            "has_children": False,
            "parent_id": parent_id,
            "conversation_label": conversation_label,
            "conversation_id": cid
          }) -%}
        {%- endfor -%}
      {%- else -%}
        {# No prompts - still add conversation with placeholder text #}
        {# This handles child conversations that only have agent responses #}
        {%- set placeholder_timestamp = conv_groups[cid][0].get("timestamp", "") -%}
        {%- set placeholder_prompt_id = conv_groups[cid][0].get("prompt_id", "") -%}
        {%- set placeholder_base_cost = prompt_base_costs.get(placeholder_prompt_id, 0.0) -%}
        {%- set placeholder_agg_cost = prompt_aggregate_costs.get(placeholder_prompt_id, 0.0) -%}
        {%- set share_pct = 100.0 if parent else 0.0 -%}
        {%- set _ = all_prompts_flat.append({
          "text": "(Agent execution)",
          "timestamp": placeholder_timestamp,
          "prompt_id": placeholder_prompt_id,
          "cid": cid,
          "level": level,
          "base_cost": placeholder_base_cost,
          "aggregate_cost": placeholder_agg_cost,
          "is_parent": parent,
          "share_pct": share_pct,
          "agent_name": agent_name,
          "has_children": False,
          "parent_id": parent_id,
          "conversation_label": conversation_label,
          "conversation_id": cid
        }) -%}
      {%- endif -%}
    {%- else -%}
      {%- set _ = cids_not_in_conv_groups.append(cid) -%}
    {%- endif -%}
  {%- endfor -%}

  {# Update has_children flag and calculate share_pct #}
  {%- set all_prompts_with_flags = [] -%}
  {%- for item in all_prompts_flat -%}
    {%- set my_prompt_id = item.get("prompt_id", "") -%}
    {%- set my_cid = item.get("cid", "") -%}
    {%- set matches = [] -%}
    {# Check if any other prompt's prompt_id starts with my_prompt_id followed by : #}
    {%- if my_prompt_id -%}
      {%- for other in all_prompts_flat -%}
        {%- set other_prompt_id = other.get("prompt_id", "") -%}
        {%- if other_prompt_id and other_prompt_id.startswith(my_prompt_id + ":") -%}
          {%- set _ = matches.append(other_prompt_id) -%}
        {%- endif -%}
      {%- endfor -%}
    {%- endif -%}
    {# Set has_children based on whether matches list is non-empty #}
    {%- set item_has_children = (matches | length) > 0 -%}
    
    {# Calculate share_pct: For root parents, 100%. For children, find root parent with same base conv_id and prompt_id #}
    {# Use a list to store share_pct because list mutations persist across Jinja2 scopes #}
    {%- set share_pct_holder = [0.0] -%}
    {%- if item.level == 0 -%}
      {# Root parent: 100% #}
      {%- set _ = share_pct_holder.append(100.0) -%}
      {%- set _ = share_pct_holder.pop(0) -%}
    {%- else -%}
      {# Child: Find root parent (level 0) with matching base conv_id and prompt_id #}
      {# Extract base conv_id (part before first :) #}
      {%- set base_cid = my_cid.split(":")[0] if ":" in my_cid else my_cid -%}
      {# Extract base prompt_id (part before first :) #}
      {%- set base_prompt_id = my_prompt_id.split(":")[0] if ":" in my_prompt_id else my_prompt_id -%}
      
      {# Find the root parent with matching base_cid and base_prompt_id #}
      {%- set found_parent = false -%}
      {%- for potential_parent in all_prompts_flat if not found_parent -%}
        {%- if potential_parent.level == 0 -%}
          {%- set parent_cid = potential_parent.get("cid", "") -%}
          {%- set parent_prompt_id = potential_parent.get("prompt_id", "") -%}
          {# Check if this parent matches our base conv_id and prompt_id #}
          {%- if parent_cid == base_cid and parent_prompt_id == base_prompt_id -%}
            {%- set found_parent = true -%}
            {%- set parent_agg = potential_parent.get("aggregate_cost", 0.0) -%}
            {%- if parent_agg > 0 and item.base_cost > 0 -%}
              {%- set calculated_share = ((item.base_cost / parent_agg) * 100.0) | round(1) -%}
              {%- set _ = share_pct_holder.append(calculated_share) -%}
              {%- set _ = share_pct_holder.pop(0) -%}
            {%- endif -%}
          {%- endif -%}
        {%- endif -%}
      {%- endfor -%}
    {%- endif -%}
    
    {%- set updated_item = dict(item, has_children=item_has_children, share_pct=share_pct_holder[0]) -%}
    {%- set _ = all_prompts_with_flags.append(updated_item) -%}
  {%- endfor -%}
  
  {# Build hierarchical display order: parents sorted by timestamp, followed by their children #}
  {%- set all_prompts_flat = [] -%}
  {%- set processed_prompt_ids = [] -%}
  
  {# Helper to recursively add children sorted by timestamp #}
  {%- macro add_children_recursive(parent_prompt_id) -%}
    {%- set direct_children = [] -%}
    {%- for item in all_prompts_with_flags -%}
      {%- set item_prompt_id = item.get("prompt_id", "") -%}
      {%- if item_prompt_id not in processed_prompt_ids and item_prompt_id and item_prompt_id.startswith(parent_prompt_id + ":") -%}
        {%- set suffix = item_prompt_id[parent_prompt_id|length + 1:] -%}
        {%- if suffix and ":" not in suffix -%}
          {# This is a direct child #}
          {%- set _ = direct_children.append(item) -%}
        {%- endif -%}
      {%- endif -%}
    {%- endfor -%}
    {# Sort children by timestamp #}
    {%- set direct_children = direct_children | sort(attribute="timestamp") -%}
    {%- for child in direct_children -%}
      {%- set child_prompt_id = child.get("prompt_id", "") -%}
      {%- set _ = all_prompts_flat.append(child) -%}
      {%- set _ = processed_prompt_ids.append(child_prompt_id) -%}
      {# Recursively add this child's children #}
      {{ add_children_recursive(child_prompt_id) }}
    {%- endfor -%}
  {%- endmacro -%}
  
  {# Get all root parents (level 0) and sort by timestamp #}
  {%- set root_parents = [] -%}
  {%- for item in all_prompts_with_flags -%}
    {%- if item.level == 0 -%}
      {%- set _ = root_parents.append(item) -%}
    {%- endif -%}
  {%- endfor -%}
  {%- set root_parents = root_parents | sort(attribute="timestamp") -%}
  
  {# Process each root parent and its children #}
  {%- for parent in root_parents -%}
    {%- set parent_prompt_id = parent.get("prompt_id", "") -%}
    {%- if parent_prompt_id not in processed_prompt_ids -%}
      {%- set _ = all_prompts_flat.append(parent) -%}
      {%- set _ = processed_prompt_ids.append(parent_prompt_id) -%}
      {# Add all children of this parent recursively #}
      {{ add_children_recursive(parent_prompt_id) }}
    {%- endif -%}
  {%- endfor -%}
  
  {# Set the final sorted list for display #}
  {%- set sorted_all_prompts = all_prompts_flat -%}

  {# Calculate overall cost and tokens #}
  {%- set overall_query = "conversationId contains '" + parent_conv_id + "' GET llm, token_usage_input_tokens, token_usage_cache_tokens, token_usage_output_tokens" -%}
  {%- set overall_data = engine.query_stream_data(
      "rda_chat_sessions",
      cfxql_query=overall_query,
      limit=10000,
      max_rows=10000
  ) -%}
  {%- set overall_input_list = [] -%}
  {%- set overall_cache_list = [] -%}
  {%- set overall_output_list = [] -%}
  {%- set overall_cost_list = [] -%}
  {%- for c in overall_data -%}
    {%- set llm_name = c.get("llm", "") | string | trim -%}
    {%- set input_tokens = (c.get("token_usage_input_tokens") or 0) | int -%}
    {%- set cache_tokens = (c.get("token_usage_cache_tokens") or 0) | int -%}
    {%- set output_tokens = (c.get("token_usage_output_tokens") or 0) | int -%}
    {%- set _ = overall_input_list.append(input_tokens) -%}
    {%- set _ = overall_cache_list.append(cache_tokens) -%}
    {%- set _ = overall_output_list.append(output_tokens) -%}
    {%- if llm_name and llm_name != "" and costs.get(llm_name) -%}
      {%- set cm = costs.get(llm_name, [0.0, 0.0]) -%}
      {%- if input_tokens > 0 or output_tokens > 0 -%}
        {%- set input_cost = (cm[0] | float) * (input_tokens | float) / 1000000.0 -%}
        {%- set output_cost = (cm[1] | float) * (output_tokens | float) / 1000000.0 -%}
        {%- set calculated_cost = input_cost + output_cost -%}
        {%- set _ = overall_cost_list.append(calculated_cost) -%}
      {%- endif -%}
    {%- endif -%}
  {%- endfor -%}
  {%- set overall_input_tokens = overall_input_list | sum -%}
  {%- set overall_cache_tokens = overall_cache_list | sum -%}
  {%- set overall_output_tokens = overall_output_list | sum -%}
  {%- set overall_cost = overall_cost_list | sum -%}

  {# Calculate max depth by getting root conversation_id from conversation_id parameter #}
  {%- set root_conv_id = parent_conv_id -%}
  {%- if conversation_id is defined and conversation_id != "" and ":" in conversation_id -%}
    {%- set root_conv_id = conversation_id.split(":")[0] -%}
  {%- elif conv_id is defined and conv_id != "" and ":" in conv_id -%}
    {%- set root_conv_id = conv_id.split(":")[0] -%}
  {%- endif -%}
  {# Query all conversation IDs containing the root #}
  {%- set depth_query = "conversationId contains '" + root_conv_id + "' GET conversationId" -%}
  {%- set depth_data = engine.query_stream_data(
      "rda_chat_sessions",
      cfxql_query=depth_query,
      limit=10000,
      max_rows=10000
  ) -%}
  {%- set unique_cids = [] -%}
  {%- for item in depth_data -%}
    {%- set cid = item.get("conversationId", "") -%}
    {%- if cid and cid not in unique_cids -%}
      {%- set _ = unique_cids.append(cid) -%}
    {%- endif -%}
  {%- endfor -%}
  {# Calculate max depth from unique CIDs - find maximum number of colons #}
  {%- set unique_cids_list = unique_cids | list -%}
  {%- set debug_colon_counts = [] -%}
  {%- for cid in unique_cids_list -%}
    {%- if cid -%}
      {%- set cid_str = cid | string -%}
      {%- set colon_count = cid_str.count(":") -%}
      {%- set _ = debug_colon_counts.append(colon_count) -%}
    {%- endif -%}
  {%- endfor -%}
  {# Get unique colon counts and find max #}
  {%- set debug_unique_colon_counts = [] -%}
  {%- for count in debug_colon_counts -%}
    {%- if count not in debug_unique_colon_counts -%}
      {%- set _ = debug_unique_colon_counts.append(count) -%}
    {%- endif -%}
  {%- endfor -%}
  {%- set debug_unique_colon_counts_list = debug_unique_colon_counts | list | sort -%}
  {# Max depth is the maximum of unique colon counts #}
  {%- if debug_unique_colon_counts_list | length > 0 -%}
    {%- set max_depth = debug_unique_colon_counts_list | max -%}
  {%- else -%}
    {%- set max_depth = 0 -%}
  {%- endif -%}
  

  {# Build hierarchical display order: process each parent instance and its children #}
  {# Display order is simply the sorted list #}
  {%- set sorted_all_prompts = all_prompts_flat -%}

  {# Calculate duration #}
  {%- set all_timestamps = convs | map(attribute="timestamp") | list -%}
  {%- set st = to_datetime(all_timestamps | min) -%}
  {%- set et = to_datetime(all_timestamps | max) -%}
  {%- set duration_str = str((et - st).to_pytimedelta()).split(".")[0] -%}

  {# Calculate current depth from conversation_id #}
  {%- set current_depth = 0 -%}
  {%- if conversation_id is defined and conversation_id != "" -%}
    {%- set current_depth = conversation_id.count(":") -%}
  {%- elif conv_id is defined and conv_id != "" -%}
    {%- set current_depth = conv_id.count(":") -%}
  {%- endif -%}

{% raw %}
  <!-- Header Section -->
  <table width="100%" border="0" cellspacing="0" cellpadding="8" style="margin:0px; margin-bottom:10px; color:var(--text-primary); font-family: Avenir, -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; border-collapse:collapse;">
    <tr>
      <td style="text-align:center; vertical-align:middle; color:var(--text-secondary); font-size:12px; width:12.5%;">
        <img src="/assets/img/icons/featureApp/svgIcons/customer.svg" style="width:15px; margin-right:5px; filter: brightness(0) invert(1);">
        <span>User</span>
      </td>
      <td style="text-align:center; vertical-align:middle; color:var(--text-secondary); font-size:12px; width:12.5%;">
        <img src="/assets/img/icons/featureApp/svgIcons/collaboration.svg" style="width:15px; margin-right:5px; filter: brightness(0) invert(1);">
        <span>Conversation Label</span>
      </td>
      <td style="text-align:center; vertical-align:middle; color:var(--text-secondary); font-size:12px; width:12.5%;">
        <img src="/assets/img/icons/featureApp/svgIcons/insights.svg" style="width:15px; margin-right:5px; filter: brightness(0) invert(1);">
        <span>Persona</span>
      </td>
      <td style="text-align:center; vertical-align:middle; color:var(--text-secondary); font-size:12px; width:12.5%;">
        <img src="/assets/img/icons/featureApp/svgIcons/schedule.svg" style="width:15px; margin-right:5px; filter: brightness(0) invert(1);">
        <span>Duration</span>
      </td>
      <td style="text-align:center; vertical-align:middle; color:var(--text-secondary); font-size:12px; width:12.5%;">
        <img src="/assets/img/icons/featureApp/svgIcons/nextSteps.svg" style="width:15px; margin-right:5px; filter: brightness(0) invert(1);">
        <span>Tokens</span>
      </td>
      <td style="text-align:center; vertical-align:middle; color:var(--text-secondary); font-size:12px; width:12.5%;">
        <img src="/assets/img/icons/featureApp/svgIcons/status.svg" style="width:15px; margin-right:5px; filter: brightness(0) invert(1);">
        <span>Total Cost</span>
      </td>
      <td style="text-align:center; vertical-align:middle; color:var(--text-secondary); font-size:12px; width:12.5%;">
        <img src="/assets/img/icons/featureApp/svgIcons/insights.svg" style="width:15px; margin-right:5px; filter: brightness(0) invert(1);">
        <span>Current Depth</span>
      </td>
      <td style="text-align:center; vertical-align:middle; color:var(--text-secondary); font-size:12px; width:12.5%;">
        <img src="/assets/img/icons/featureApp/svgIcons/insights.svg" style="width:15px; margin-right:5px; filter: brightness(0) invert(1);">
        <span>Max Depth</span>
      </td>
    </tr>
    <tr>
      <td style="text-align:center; font-size:14px; font-weight:600; color:var(--text-primary); width:12.5%;">{% endraw %}{{ convs[0].get("USER_ID", "") }}{% raw %}</td>
      <td style="text-align:center; font-size:14px; font-weight:600; color:var(--text-primary); width:12.5%;">{% endraw %}{{ convs[0].get("conversationLabel", "") }}{% raw %}</td>
      <td style="text-align:center; font-size:14px; font-weight:600; color:var(--text-primary); width:12.5%;">{% endraw %}{%- set persona_value = convs[0].get("persona", "") -%}{%- set ai_project_name = convs[0].get("ai_project_name", "") -%}{%- if "/" in persona_value -%}{{ persona_value }}{%- elif ai_project_name and persona_value -%}{{ ai_project_name }}/{{ persona_value }}{%- else -%}{{ persona_value }}{%- endif -%}{% raw %}</td>
      <td style="text-align:center; font-size:14px; font-weight:600; color:var(--text-primary); width:12.5%;">{% endraw %}{{ duration_str }}{% raw %}</td>
      <td style="text-align:center; font-size:12px; font-weight:normal; color:var(--text-primary); width:12.5%;">
        <center>
          <table border="0" cellspacing="0" cellpadding="5" style="border-collapse:collapse;">
            <tr>
              <td style="border-bottom:1px solid var(--border-color); color:var(--text-secondary); font-size:11px;">Input</td>
              <td style="border-bottom:1px solid var(--border-color); color:var(--text-secondary); font-size:11px;">Cache</td>
              <td style="border-bottom:1px solid var(--border-color); color:var(--text-secondary); font-size:11px;">Output</td>
            </tr>
            <tr>
              <td style="color:var(--text-primary); font-size:12px;">{% endraw %}{{ "{:,}".format(overall_input_tokens | int) }}{% raw %}</td>
              <td style="color:var(--text-primary); font-size:12px;">{% endraw %}{{ "{:,}".format(overall_cache_tokens | int) }}{% raw %}</td>
              <td style="color:var(--text-primary); font-size:12px;">{% endraw %}{{ "{:,}".format(overall_output_tokens | int) }}{% raw %}</td>
            </tr>
          </table>
        </center>
      </td>
      <td style="text-align:center; font-size:14px; font-weight:600; color:var(--text-primary); width:12.5%;">$ {% endraw %}{{ overall_cost | round(4) }}{% raw %}</td>
      <td style="text-align:center; font-size:14px; font-weight:600; color:var(--text-primary); width:12.5%;">{% endraw %}{{ current_depth }}{% raw %}</td>
      <td style="text-align:center; font-size:14px; font-weight:600; color:var(--text-primary); width:12.5%;">{% endraw %}{{ max_depth }}{% raw %}</td>
    </tr>
  </table>

  <!-- Display prompts -->
  <div style="padding:10px 0px 10px 20px;">
    {% endraw %}{%- for prompt_item in sorted_all_prompts -%}
      {%- set indent = prompt_item.level * 50 -%}
