      {%- set highlight_cid = conversation_id if (conversation_id is defined and conversation_id != "") else (conv_id if (conv_id is defined and conv_id != "") else "") -%}
      {%- set is_highlighted = (prompt_item.cid == highlight_cid) if highlight_cid != "" else False -%}
      {%- set dot_color = "#00ff00" if is_highlighted else ("#0066cc" if prompt_item.is_parent else "#66b3ff") -%}
      {%- set dot_size = "10px" -%}
      {%- set dot_glow = "0 0 8px rgba(0,255,0,0.9), 0 0 15px rgba(0,255,0,0.6)" if is_highlighted else "0 0 6px rgba(77,166,255,0.5)" -%}
      {%- set dot_border = "2px solid rgba(255,255,255,0.4)" if is_highlighted else "1px solid rgba(255,255,255,0.15)" -%}
