      <!-- Separator line for each top-level parent -->
      <div style="margin:10px 0 10px 0; border-top:2px solid var(--border-separator); opacity:0.8;"></div>
      {% endraw %}{%- endif -%}{% raw %}
      
      {% endraw %}{%- if prompt_item.has_children -%}{% raw %}
