        <!-- Left section: Indented content with arrow, dot, agent name, and prompt -->
        <div style="flex:1; min-width:0; max-width:calc(100% - 290px); padding-left:{% endraw %}{{ indent }}{% raw %}px; display:flex; align-items:center; gap:8px; padding-right:20px;">
          <span class="collapse-arrow" onclick="toggleChildren('{% endraw %}{{ prompt_item.prompt_id }}{% raw %}')" style="color:var(--accent-orange); font-size:18px; font-weight:bold; line-height:1; flex-shrink:0; width:24px; text-align:center; display:inline-block; transition: transform 0.2s ease; cursor:pointer;">▼</span>
          <div style="display:flex; align-items:center; flex-shrink:0; gap:4px;">
            <span style="width:{% endraw %}{{ dot_size }}{% raw %}; height:{% endraw %}{{ dot_size }}{% raw %}; border-radius:50%; background-color:{% endraw %}{{ dot_color }}{% raw %}; display:inline-block; flex-shrink:0; box-shadow:{% endraw %}{{ dot_glow }}{% raw %}; border:{% endraw %}{{ dot_border }}{% raw %};"></span>
          </div>
          <div class="text-container" style="flex:1; min-width:0; overflow:hidden;">
            <div style="font-weight:600; font-size:14px; white-space:nowrap; overflow:hidden; text-overflow:ellipsis; line-height:1.4;">
              <span onclick="launchConversationDetails('{% endraw %}{{ current_cid }}{% raw %}', '{% endraw %}{{ prompt_item.conversation_label | replace("'", "\\'") }}{% raw %}')" style="color:{% endraw %}{{ agent_color }}{% raw %}; cursor:pointer; transition: opacity 0.2s ease;" onmouseover="this.style.opacity='0.7'" onmouseout="this.style.opacity='1'">{% endraw %}{{ prompt_item.agent_name }}{% raw %}</span>
              <span onclick="event.stopPropagation(); showMessageDetails('{% endraw %}{{ current_cid }}{% raw %}', '{% endraw %}{{ prompt_item.prompt_id }}{% raw %}', '{% endraw %}{{ prompt_item.conversation_label | replace("'", "\\'") }}{% raw %}')" style="display:none; width:16px; height:16px; line-height:16px; text-align:center; background-color:var(--accent-blue); color:var(--bg-primary); border-radius:50%; font-size:10px; font-weight:bold; margin-left:6px; cursor:pointer; transition: all 0.2s ease; z-index:10; position:relative;" onmouseover="this.style.backgroundColor='var(--accent-blue-light)'; this.style.transform='scale(1.1)'" onmouseout="this.style.backgroundColor='var(--accent-blue)'; this.style.transform='scale(1)'">i</span>
              <span style="color:var(--text-secondary); font-weight:normal; font-size:12px; margin-left:6px;">•</span>
              <span class="prompt-text" onclick="event.stopPropagation(); togglePromptExpansion(this);" style="color:var(--text-secondary); font-weight:normal; font-size:12px; margin-left:6px; cursor:pointer;">{% endraw %}{{ current_text }}{% raw %}</span>
            </div>
          </div>
        </div>
        <!-- Right section: Fixed-width cost columns -->
        <div style="display:flex; gap:12px; flex-shrink:0; width:290px; align-items:center; padding-right:28px;">
          <div style="display:flex; flex-direction:column; gap:2px; width:75px; flex-shrink:0;">
            {% endraw %}{%- if loop.first -%}{% raw %}
            <div style="color:var(--text-primary); font-size:10px; font-weight:600; text-align:center; height:14px; line-height:14px; display:flex; align-items:center; justify-content:center;">Aggregate Cost</div>
            {% endraw %}{%- endif -%}{% raw %}
            <div style="color:var(--text-primary); font-size:11px; white-space:nowrap; font-weight:600; padding:7px 8px; background:var(--bg-card); border-radius:6px; border:1px solid var(--border-color); box-shadow:0 2px 4px var(--shadow); width:100%; text-align:center; box-sizing:border-box; min-height:30px; max-height:30px; height:30px; display:flex; align-items:center; justify-content:center;">${% endraw %}{{ prompt_item.aggregate_cost | round(2) }}{% raw %}</div>
          </div>
          <div style="display:flex; flex-direction:column; gap:2px; width:75px; flex-shrink:0;">
            {% endraw %}{%- if loop.first -%}{% raw %}
            <div style="color:var(--text-primary); font-size:10px; font-weight:600; text-align:center; height:14px; line-height:14px; display:flex; align-items:center; justify-content:center;">Base Cost</div>
