              <div style="display:flex; align-items:center; gap:4px; width:100%;">
                <div style="flex:1; height:10px; background-color:var(--bg-secondary); border-radius:5px; overflow:hidden; border:1px solid var(--border-light); min-width:0;">
                  <div style="height:100%; background:linear-gradient(90deg, var(--accent-blue-dark) 0%, var(--accent-blue) 100%); width:{% endraw %}{{ [prompt_item.share_pct, 100] | min }}{% raw %}%; transition: width 0.3s ease; box-shadow:0 0 6px rgba(77,166,255,0.4);"></div>
                </div>
                <span style="color:var(--accent-blue); font-size:10px; font-weight:600; min-width:32px; text-align:right; flex-shrink:0;">{% endraw %}{{ prompt_item.share_pct }}{% raw %}%</span>
              </div>
            </div>
          </div>
        </div>
      </div>
      {% endraw %}{%- else -%}{% raw %}
      <!-- Regular child without children -->
      <div data-prompt-id="{% endraw %}{{ prompt_item.prompt_id }}{% raw %}" data-cid="{% endraw %}{{ prompt_item.cid }}{% raw %}" style="margin-bottom:1px; padding-top:1px; padding-bottom:1px; color:var(--text-primary); font-size:12px; line-height:1.4; border-left:3px solid transparent; transition: background-color 0.2s ease; font-family: Avenir, -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; display:flex; align-items:center;">
        <!-- Left section: Indented content with spacer, dot, agent name, and prompt -->
        <div style="flex:1; min-width:0; max-width:calc(100% - 290px); padding-left:{% endraw %}{{ indent }}{% raw %}px; display:flex; align-items:center; gap:8px; padding-right:20px;">
          <span style="width:24px; flex-shrink:0;"></span>
          <div style="display:flex; align-items:center; flex-shrink:0; gap:4px;">
            <span style="width:{% endraw %}{{ dot_size }}{% raw %}; height:{% endraw %}{{ dot_size }}{% raw %}; border-radius:50%; background-color:{% endraw %}{{ dot_color }}{% raw %}; display:inline-block; flex-shrink:0; box-shadow:{% endraw %}{{ dot_glow }}{% raw %}; border:{% endraw %}{{ dot_border }}{% raw %};"></span>
          </div>
          <div class="text-container" style="flex:1; min-width:0; overflow:hidden;">
            <div style="font-weight:600; font-size:14px; white-space:nowrap; overflow:hidden; text-overflow:ellipsis; line-height:1.4;">
              <span onclick="launchConversationDetails('{% endraw %}{{ current_cid }}{% raw %}', '{% endraw %}{{ prompt_item.conversation_label | replace("'", "\\'") }}{% raw %}')" style="color:{% endraw %}{{ agent_color }}{% raw %}; cursor:pointer; transition: opacity 0.2s ease;" onmouseover="this.style.opacity='0.7'" onmouseout="this.style.opacity='1'">{% endraw %}{{ prompt_item.agent_name }}{% raw %}</span>
              <span onclick="event.stopPropagation(); showMessageDetails('{% endraw %}{{ current_cid }}{% raw %}', '{% endraw %}{{ prompt_item.prompt_id }}{% raw %}', '{% endraw %}{{ prompt_item.conversation_label | replace("'", "\\'") }}{% raw %}')" style="display:none; width:16px; height:16px; line-height:16px; text-align:center; background-color:var(--accent-blue); color:var(--bg-primary); border-radius:50%; font-size:10px; font-weight:bold; margin-left:6px; cursor:pointer; transition: all 0.2s ease; z-index:10; position:relative;" onmouseover="this.style.backgroundColor='var(--accent-blue-light)'; this.style.transform='scale(1.1)'" onmouseout="this.style.backgroundColor='var(--accent-blue)'; this.style.transform='scale(1)'">i</span>
              <span style="color:var(--text-secondary); font-weight:normal; font-size:12px; margin-left:6px;">•</span>
              <span class="prompt-text" onclick="event.stopPropagation(); togglePromptExpansion(this);" style="color:var(--text-secondary); font-weight:normal; font-size:12px; margin-left:6px; cursor:pointer;">{% endraw %}{{ current_text }}{% raw %}</span>
            </div>
          </div>
        </div>
        <!-- Right section: Fixed-width cost columns (with spacer for Aggregate Cost alignment) -->
        <div style="display:flex; gap:12px; flex-shrink:0; width:290px; align-items:center; padding-right:28px;">
          <!-- Spacer to align with Aggregate Cost column -->
          <div style="width:75px; flex-shrink:0;"></div>
          <div style="display:flex; flex-direction:column; gap:2px; width:75px; flex-shrink:0;">
            {% endraw %}{%- if loop.first -%}{% raw %}
            <div style="color:var(--text-primary); font-size:10px; font-weight:600; text-align:center; height:14px; line-height:14px; display:flex; align-items:center; justify-content:center;">Base Cost</div>
            {% endraw %}{%- endif -%}{% raw %}
            <div style="color:var(--text-primary); font-size:11px; white-space:nowrap; font-weight:600; padding:7px 8px; background:var(--bg-card); border-radius:6px; border:1px solid var(--border-color); box-shadow:0 2px 4px var(--shadow); width:100%; text-align:center; box-sizing:border-box; min-height:30px; max-height:30px; height:30px; display:flex; align-items:center; justify-content:center;">${% endraw %}{{ prompt_item.base_cost | round(2) }}{% raw %}</div>
          </div>
          <div style="display:flex; flex-direction:column; gap:2px; width:100px; flex-shrink:0;">
            {% endraw %}{%- if loop.first -%}{% raw %}
            <div style="color:var(--accent-blue); font-size:10px; font-weight:600; text-align:center; height:14px; line-height:14px; display:flex; align-items:center; justify-content:center;">Cost Share</div>
            {% endraw %}{%- endif -%}{% raw %}
            <div style="padding:7px 6px; background:var(--bg-card); border-radius:6px; border:1px solid var(--border-color); box-shadow:0 2px 4px var(--shadow); min-height:30px; max-height:30px; height:30px; display:flex; align-items:center; width:100%; box-sizing:border-box;">
              <div style="display:flex; align-items:center; gap:4px; width:100%;">
                <div style="flex:1; height:10px; background-color:var(--bg-secondary); border-radius:5px; overflow:hidden; border:1px solid var(--border-light); min-width:0;">
                  <div style="height:100%; background:linear-gradient(90deg, var(--accent-blue-dark) 0%, var(--accent-blue) 100%); width:{% endraw %}{{ [prompt_item.share_pct, 100] | min }}{% raw %}%; transition: width 0.3s ease; box-shadow:0 0 6px rgba(77,166,255,0.4);"></div>
                </div>
                <span style="color:var(--accent-blue); font-size:10px; font-weight:600; min-width:32px; text-align:right; flex-shrink:0;">{% endraw %}{{ prompt_item.share_pct }}{% raw %}%</span>
              </div>
            </div>
          </div>
        </div>
      </div>
      {% endraw %}{%- endif -%}{% raw %}
      
      {% endraw %}
    {%- endfor -%}{% raw %}
  </div>
  
{% endraw %}
{%- else -%}
  <b style="color:var(--text-primary);">Conversation with ID containing '{% raw %}{{ parent_conv_id }}{% endraw %}' not found. May have been purged from the stream.</b>
{%- endif -%}{% raw %}

</div>
{% endraw %}
